-- Verify:
SELECT COUNT(*),
       ROUND(AVG(hrc_score)::numeric, 2)                AS avg_hrc_current,
       ROUND(AVG(hrc_historical_reference)::numeric, 2) AS avg_hrc_historical,
       ROUND(AVG(hrc_historical_reference - hrc_score)::numeric, 2) AS avg_degradation
FROM hrc_tiles
WHERE longitude BETWEEN -5.4 AND -2.6
  AND latitude  BETWEEN 51.3 AND 53.5
  AND hrc_historical_reference IS NOT NULL;